const DESTINATION_SURCHARGES = {
  peninsula: 0,
  islands_ceuta_melilla: 5,
  europe: 10,
  international: 15,
};

/**
 * Writes JSON data to localStorage safely.
 * Keeps checkout usable when storage is unavailable or full.
 * @param {string} key
 * @param {unknown} value
 */
function safeWriteStorage(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // Best-effort persistence only.
  }
}

/**
 * Basic Luhn validation to reduce malformed card input before submission.
 * @param {string} cardNumber
 * @returns {boolean}
 */
function isValidCardLuhn(cardNumber) {
  let sum = 0;
  let shouldDouble = false;

  for (let i = cardNumber.length - 1; i >= 0; i -= 1) {
    let digit = Number.parseInt(cardNumber[i], 10);
    if (Number.isNaN(digit)) {
      return false;
    }

    if (shouldDouble) {
      digit *= 2;
      if (digit > 9) {
        digit -= 9;
      }
    }

    sum += digit;
    shouldDouble = !shouldDouble;
  }

  return sum % 10 === 0;
}

/** Formats card digits into groups of four for readability. */
function formatCardNumber(value) {
  const digits = String(value || '').replace(/\D/g, '').slice(0, 16);
  return digits.replace(/(\d{4})(?=\d)/g, '$1 ');
}

/** Generates a stable order id with UUID when available. */
function buildOrderId() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }

  const randomSuffix = Math.random().toString(36).slice(2, 8);
  return `${Date.now()}-${randomSuffix}`;
}

/** Generates a user-facing order number from customer name. */
export function buildOrderNumber(customerName) {
  const safePrefix = String(customerName || '').trim().split(' ')[0] || 'PEDIDO';
  const randomSuffix = Math.random().toString(36).slice(2, 8).toUpperCase();
  return `${safePrefix}-${randomSuffix}`;
}

/** Returns whether checkout submit must be blocked due to empty cart. */
export function shouldBlockCheckoutSubmit(cartLength) {
  return Number(cartLength) <= 0;
}

/**
 * Saves a completed order to local history.
 * @param {{ name: string }} formData
 * @param {Array<{ id: number|string, name: string, quantity: number, price: number }>} items
 * @param {number} total
 */
function persistOrder(formData, items, subtotal, discountAmount, finalPrice, coupon, orderNumber) {
  const newOrder = {
    id: buildOrderId(),
    orderNumber,
    createdAt: new Date().toISOString(),
    customerName: formData.name.trim(),
    totalItems: items.reduce((sum, item) => sum + item.quantity, 0),
    subtotalPrice: subtotal,
    discountAmount,
    couponCode: coupon?.code ?? null,
    totalPrice: finalPrice,
    items: items.map((item) => ({
      id: item.id,
      name: item.name,
      quantity: item.quantity,
      price: item.price,
      image: item.image,
    })),
  };

  try {
    const rawOrders = localStorage.getItem(ORDERS_STORAGE_KEY);
    const currentOrders = rawOrders ? JSON.parse(rawOrders) : [];
    const safeOrders = Array.isArray(currentOrders) ? currentOrders : [];
    // Cap history at MAX_ORDERS to avoid unbounded localStorage growth.
    const trimmedOrders = [newOrder, ...safeOrders].slice(0, MAX_ORDERS);
    safeWriteStorage(ORDERS_STORAGE_KEY, trimmedOrders);
  } catch {
    safeWriteStorage(ORDERS_STORAGE_KEY, [newOrder]);
  }
}

